import * as React from "react";
import moment from "moment";
import "moment/locale/ja";
import Markdown from "markdown-to-jsx";

export interface Props {
  created: Date;
  modified: Date;
  title: string;
  description: string;
  tags?: React.ReactNode;
  isExistExtension?: boolean;
  appendView?: React.ReactNode;
  onReadMore?: () => void;
  onTranslate?: () => void;
  onDelete?: () => void;
  onInstallExtension?: () => void;
}
const ContentDetail = ({
  title,
  description,
  created,
  modified,
  appendView,
  onReadMore,
  onTranslate,
  onDelete,

  // new
  isExistExtension,
  onInstallExtension,

  tags
}: Props) => {
  let actionButton: React.ReactNode;

  if (isExistExtension) {
    actionButton = (
      <button className="button is-primary" onClick={onTranslate}>
        翻訳先に移動して翻訳
      </button>
    );
  } else {
    actionButton = (
      <button className="button is-primary" onClick={onInstallExtension}>
        翻訳するためにchrome-extensionを導入する
      </button>
    );
  }

  const inlineTitle = title !== "" ? title : "未設定";
  const inlineDescription = description !== "" ? description : "詳細なし";

  return (
    <div>
      <div className="content">
        <div className="level">
          <div className="level-left">
            <div className="level-item ">{actionButton}</div>
          </div>
          <div className="level-right">
            <div className="level-item ">
              {onDelete && (
                <button className="button is-danger" onClick={onDelete}>
                  削除
                </button>
              )}
            </div>
          </div>
        </div>
        <br />
        <div className="level">
          <div className="level-left"> </div>
          <div className="level-right">
            <div className="level-item is-small">
              <small>作成: {moment(created).fromNow()} </small>
            </div>
            <div className="level-item is-small">
              <small>更新: {moment(modified).fromNow()}</small>
            </div>
          </div>
        </div>
        <h1>{inlineTitle}</h1>

        {tags && (
          <div className="field is-grouped is-grouped-multiline">{tags}</div>
        )}
        <Markdown>{`\n${inlineDescription}`}</Markdown>
        <br />
      </div>
      {appendView ? (
        appendView
      ) : (
        <button className="button is-fullwidth is-small" onClick={onReadMore}>
          翻訳を見てみる
        </button>
      )}
    </div>
  );
};

export default ContentDetail;
