import { connect } from 'react-redux';
import * as reducers from '../../../reducers';
import { ActionDispatcherBase } from '../../common';
// UI
import UserInfo from './userInfo';
// actions
// import * as actions from '../../../actions';
// router
import { withRouter, RouteComponentProps } from 'react-router-dom';

export class ActionDispatcher extends ActionDispatcherBase {
}

export default withRouter(connect(
    (state: reducers.State) => ({ state }),
    (dispatch) => ({ dispatch }),
    ({ state }, { dispatch }, ownProps: RouteComponentProps<{contentID: string}>) => ({ 
        contentID: ownProps.match.params.contentID,
        contentDetail: state.contentDetail,
        accounts: state.accounts,
        actions: new ActionDispatcher(dispatch, state),
    })
)(UserInfo));
