import * as React from "react";

interface TextFieldProps {
  placeHolder?: string;
  defaultValue?: string;
  changeValue?: (value: string) => void;
  error?: string;
}
const TextField = (props: TextFieldProps) => {
  const { placeHolder, defaultValue, changeValue, error } = props;
  return (
    <div className="field">
      <label className="label">{placeHolder}</label>
      <div className="control has-icons-left has-icons-right">
        <input
          className={`input ${error && "is-danger"}`}
          type="text"
          placeholder={placeHolder}
          value={defaultValue}
          onChange={e => {
            if (changeValue) {
              changeValue(e.target.value);
            }
          }}
        />
        <span className="icon is-small is-left">
          <i className="fa fa-user" />
        </span>
        <span className="icon is-small is-right">
          <i className="fa fa-check" />
        </span>
      </div>
      {error && <p className="help is-danger">{error}</p>}
    </div>
  );
};

async function convert(file: File) {
  return new Promise<string>(resolve => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onloadend = () => {
      resolve(reader.result);
    };
  });
}

const bindChangeEvent = async (
  fileInput: HTMLInputElement | null,
  onChangeFile?: (buff: string) => void
) => {
  if (!onChangeFile) {
    return;
  }
  if (!fileInput) {
    return;
  }

  if (fileInput.files) {
    const file = fileInput.files[0];
    let buffer = await convert(file);
    onChangeFile(buffer);
  }
};

interface FileFeildProps {
  placeHolder?: string;
  defaultValue?: string;
  changeFile?: (buff: string) => void;
  error?: string;
}
const FileField = (props: FileFeildProps) => {
  const { changeFile, defaultValue, error, placeHolder } = props;
  return (
    <div className="field">
      <label className="label">{placeHolder}</label>
      <div className="file">
        <label className="file-label">
          <input
            className="file-input"
            type="file"
            onChange={e => {
              bindChangeEvent(e.target, changeFile);
            }}
          />
          <span className="file-cta">
            <span className="file-icon">
              <i className="fa fa-upload" />
            </span>
            <span className="file-label">{defaultValue}</span>
          </span>
        </label>
      </div>
      {error && <p className="help is-danger">{error}</p>}
    </div>
  );
};

export interface Props {
  avatar: string;
  name: string;
  onSave?: () => void;
  onReset?: () => void;
  onChageFile?: (file: string) => void;
  onChangeName?: (name: string) => void;
  disableButton?: boolean;
  errMessages?: {
    file?: string;
    name?: string;
  };
}

class MyAccount extends React.Component<Props> {
  render() {
    const props = this.props;
    return (
      <div className="box">
        <p className="title is-6">アカウント情報の修正</p>
        <article className="media">
          <div className="media-left">
            <figure className="image is-64x64">
              <img src={props.avatar} alt="Image" />
            </figure>
          </div>
          <div className="media-content">
            <div className="content is-small">
              <FileField
                placeHolder="Image"
                defaultValue="画像ファイル"
                changeFile={props.onChageFile}
                error={props.errMessages && props.errMessages.file}
              />

              <TextField
                placeHolder="Name"
                defaultValue={props.name}
                changeValue={props.onChangeName}
                error={props.errMessages && props.errMessages.name}
              />
              <div className="field is-grouped">
                <div className="control">
                  <button
                    className="button is-primary is-spaced"
                    onClick={props.onSave}
                    disabled={props.disableButton}
                  >
                    Save
                  </button>
                </div>
                <div className="control">
                  <button
                    className="button"
                    onClick={props.onReset}
                    disabled={props.disableButton}
                  >
                    Reset
                  </button>
                </div>
              </div>
            </div>
          </div>
        </article>
      </div>
    );
  }

  changeFile = async (fileInput: HTMLInputElement | null) => {
    if (!this.props.onChageFile) {
      return;
    }

    if (fileInput) {
      if (fileInput.files) {
        const file = fileInput.files[0];
        let buffer = await convert(file);
        this.props.onChageFile(buffer);
      }
    }
  };
  changeName = (name: string) => {
    if (!this.props.onChangeName) {
      return;
    }
    this.props.onChangeName(name);
  };
}

export default MyAccount;
