import * as React from "react";

import ContentDetailBase from "taiyaq-ui/src/web/contentDetail";
import Tag from "taiyaq-ui/src/web/contentDetail/tag";
import Cell from "taiyaq-ui/src/web/contentDetail/translationCell";
import DeleteModal from "taiyaq-ui/src/web/modal/delete";
import { Articles } from "taiyaq-ui/src/web2/article";

// actions
import { ActionDispatcher } from "./index";
import * as api from "taiyaq-web-api";
import { toRawString, TransPair } from "taiyaq-node";

import LoginModel from "../../../models/login";
import TagsModel from "../../../models/tags";

export interface Props extends React.Props<{}> {
  login: LoginModel;
  contentID: string;
  isExistExtension: boolean;
  contentTiny: api.ContentTiny | undefined;
  content: api.Content | undefined;
  tags: TagsModel;
  actions: ActionDispatcher;
}

type Content = api.ContentTiny | api.Content | undefined;

export interface State {
  isConfirmDelete: boolean;
}
export default class ContentDetail<T extends Props> extends React.Component<
  T,
  State
> {
  render() {
    const { login, isExistExtension } = this.props;
    const { isConfirmDelete } = this.state;

    let onDelete: undefined | (() => void) = undefined;

    const content = this.getContent();
    if (content === undefined) {
      this.props.actions.loadData(this.props.contentID);
      return null;
    }
    if (login.isLogin() && content.autherGoogleID == login.googleUserID()) {
      onDelete = this.onDelete;
    }

    const translations = this.getTranslations();
    const tags = this.props.tags.list
      .toArray()
      .map((t: api.Tag) => (
        <Tag key={t.name} name={t.name} count={t.useCount} />
      ));

    return (
      <Articles>
        <DeleteModal
          isActive={isConfirmDelete}
          onCancel={this.onDeleteCancel}
          onDelete={this.onDeletePerform}
        />
        <ContentDetailBase
          title={content.title}
          tags={tags}
          description={content.description}
          created={content.created}
          modified={content.modified}
          onReadMore={this.props.actions.loadData(content.id)}
          onTranslate={() => this.props.actions.sendToExteion(content)}
          onDelete={onDelete} // 混乱を招く気がする canDeleteしたいがonDeleteでもある。死ね
          appendView={translations}
          isExistExtension={isExistExtension}
          onInstallExtension={() => this.props.actions.installExtension()}
        />
      </Articles>
    );
  }

  constructor(props: T) {
    super(props);
    const { contentID, contentTiny, content } = props;
    this.state = {
      isConfirmDelete: false
    };

    props.actions.checkExistExtension();

    // 何の準備もできていないならデータを取得する
    if (contentTiny === undefined && content === undefined) {
      props.actions.loadData(contentID)();
    } else {
      let c = this.getContent();
      if (c) {
        this.props.actions.getTags(c.tags);
      }
    }
  }
  onDelete = () => {
    this.setState({ isConfirmDelete: true });
  };
  onDeleteCancel = () => {
    this.setState({ isConfirmDelete: false });
  };
  onDeletePerform = () => {
    const content = this.getContent();
    if (content === undefined) {
      return;
    }
    this.props.actions.runDelete(content.id);
    this.setState({ isConfirmDelete: false });
  };
  makeTranslation = (pair: TransPair, i: number) => {
    return (
      <Cell
        key={i}
        base={toRawString(pair.base)}
        translate={toRawString(pair.trans)}
      />
    );
  };
  getContent(): Content {
    const { contentTiny, content } = this.props;
    let commonContent: Content;

    if (contentTiny) {
      commonContent = contentTiny;
    } else if (content) {
      commonContent = content;
    }
    return commonContent;
  }

  getTranslations(): JSX.Element | undefined {
    const { content } = this.props;
    if (content === undefined) {
      return;
    }
    try {
      const pairs = JSON.parse(content.pairs) as TransPair[];
      return <div>{pairs.map(this.makeTranslation)}</div>;
    } catch (e) {
      console.warn("parse err", e);
    }
  }
}
