import { RouteComponentProps } from "react-router-dom";

import { ExtensionIDs } from "../../../../settings";

const installExtension = async () => {
  return new Promise((resolve, reject) => {
    chrome.webstore.install(
      "",
      () => {
        return resolve();
      },
      (err, errcode) => {
        return reject(err);
      }
    );
  });
};

export class ActionDispatcher extends ActionDispatcherBase {
  notExistAccounts(accountIDs: string[]): string[] {
    const existAccounts = this.state.accounts.accounts;
    const notExistIDs = uniq(accountIDs).filter(id => !existAccounts.has(id));
    return notExistIDs;
  }

  async getTags(tagNames: string[]) {
    // const option = await this.getFetchOption();
    const stateTags = this.state.tags;
    for (let i = 0; i < tagNames.length; i++) {
      let result = stateTags.list.get(tagNames[i]);
      if (!result) {
        let t: api.Tag;
        try {
          t = await this.tagApi.tagShow({
            name: encodeURIComponent(tagNames[i])
          });
        } catch (e) {
          console.error("error in tagShow", e);
          t = {
            name: tagNames[i],
            useCount: 1,
            followers: []
          };
        }
        this.dispatch(actions.setTag(t));
      }
    }
  }

  loadData = (contentID: string) => async () => {
    const option = await this.getFetchOption();
    try {
      const content = await this.contentApi.contentShow({ contentID }, option);
      this.dispatch(actions.setContent(content));
      await this.getTags(content.tags);
    } catch (e) {
      this.showErrorMessage("存在しない翻訳を開こうとしました");
    }
  };

  checkExistExtension = async () => {
    const existExtension = await this.existTaiyaqExtension();
    this.dispatch(ContentDActions.setExistExtension(existExtension));
  };

  isContentTiny(
    content: api.Content | api.ContentTiny
  ): content is api.ContentTiny {
    if ((content as api.Content).pairs) {
      return false;
    }
    return true;
  }
  isContent(content: api.Content | api.ContentTiny): content is api.Content {
    if ((content as api.Content).pairs) {
      return true;
    }
    return false;
  }
  async runDelete(contentID: string) {
    const option = await this.getFetchOption();
    await this.contentApi.contentDelete({ contentID }, option);

    return;
  }

  async installExtension() {
    try {
      await installExtension();
      console.log("installed extension");
      await this.checkExistExtension();
      location.reload();
    } catch (e) {
      console.log("in installExtension err = ", e);
    }
  }

  async sendToExteion(content: api.Content | api.ContentTiny) {
    if (this.isContentTiny(content)) {
      const contentID = content.id;
      content = await this.contentApi.contentShow({ contentID });
    }

    if (this.isContent(content)) {
      for (const extensionID of ExtensionIDs) {
        console.log(`send content ${content.id} to ${extensionID}`);
        await this.sendMessage(
          extensionID,
          actions.sendContentToExtension(content)
        );
        // console.log('resp', resp);
      }
    }
  }
}

