// import * as api from 'taiyaq-web-api';
import { reducerWithInitialState } from "typescript-fsa-reducers";
// import { combineReducers } from 'redux-immutable';
// import * as Immutable from 'immutable';

// actions
import * as actions from "../../../actions";
import * as contentDActions from "./actions";

// models
// import Login from '../../models/login';
// import Feeds from '../../models/feeds';
// import Accounts from '../../models/accounts';
import ContentDetailModel from "./model";

const contentDetail = reducerWithInitialState(new ContentDetailModel())
  .case(actions.setContent, (state, payload) => state.setContent(payload))
  .case(actions.setContentTiny, (state, payload) =>
    state.setContentTiny(payload)
  )
  .case(contentDActions.setExistExtension, (state, payload) =>
    state.setExistExtension(payload)
  );

export default contentDetail;
