import * as React from 'react';
// UI
import Main from './containers';
import AutoClose from './containers/autoClose';

// router
import { BrowserRouter as Router, Route } from 'react-router-dom';
class App extends React.Component {
  mainRoots = [
    '/', 
    '/main', 
    '/mine', 
    '/contents/:contentID', 
    '/tags/:tagName', 
    '/search', 
    '/my_account',
  ];
  render() {
    return (
      <Router>
        <div>
          {/* chrome-extensionでのログイン専用のロジック */}
          <Route key="/autoclose" exact path="/autoclose" component={AutoClose} />
          {/* <Route key="/about" exact path="/about" component={About} /> */}
          {
            this.mainRoots.map(
              url => (<Route key={url} exact path={url} component={Main} />)
            )
          }
        </div>
      </Router>
    );
  }
}

export default App;
