import * as React from "react";
import { NavbarBrand, NavbarStart, NavbarEnd } from "./common";

export interface ActionPairProps {
  title: string;
  onAction: () => void;
}

export const Action = ({ title, onAction }: ActionPairProps) => (
  <a className="navbar-item" style={{ padding: "0 2rem" }} onClick={onAction}>
    {title}
  </a>
);

export interface NavibarProps {
  imgURL: string;
  isLogin?: boolean;
  onLogin?: () => void;
  onLogout?: () => void;
  actions?: ActionPairProps[];
}

export interface NavibarState {
  isMenuOpen: boolean;
}

const LoginLogoutButton = ({
  isLogin,
  isWhite,
  onClick
}: {
  isLogin?: boolean;
  isWhite?: boolean;
  onClick?: () => void;
}) => (
  <a
    className={`button ${isWhite ? "" : "is-white"} is-outlined`}
    onClick={onClick}
  >
    <span className="icon">
      <i className="fab fa-google" />
    </span>
    <span>{!isLogin ? "Login" : "Logout"}</span>
  </a>
);

export default class Navibar extends React.Component<
  NavibarProps,
  NavibarState
> {
  constructor(props: NavibarProps) {
    super(props);
    this.state = {
      isMenuOpen: false
    };
  }
  handleToggleMenu = () => {
    this.setState({ isMenuOpen: !this.state.isMenuOpen });
  };
  render() {
    const { imgURL, isLogin, onLogin, onLogout, actions } = this.props;
    const { isMenuOpen } = this.state;
    return (
      <nav
        className="navbar is-primary"
        role="navigation"
        aria-label="main navigation"
      >
        <div
          className="container"
          style={{ borderBottom: "1px solid #E6EAEE" }}
        >
          <NavbarBrand>
            <a className="navbar-item" href="/">
              <img src={imgURL} alt="taiyaq" width={112} height={28} />
            </a>
            <div
              className={`navbar-burger ${isMenuOpen ? "is-active" : ""}`}
              onClick={() => this.handleToggleMenu()}
            >
              <span />
              <span />
              <span />
            </div>
          </NavbarBrand>
          <div className={`navbar-menu  ${isMenuOpen ? "is-active" : ""} `}>
            <NavbarStart>
              {actions &&
                actions.map(action => (
                  <Action key={action.title} {...action} />
                ))}
            </NavbarStart>
            <NavbarEnd>
              <div className="navbar-item">
                <div className="field is-grouped">
                  <p className="control">
                    <LoginLogoutButton
                      isLogin={isLogin}
                      isWhite={isMenuOpen}
                      onClick={!isLogin ? onLogin : onLogout}
                    />
                  </p>
                </div>
              </div>
            </NavbarEnd>
          </div>
        </div>
      </nav>
    );
  }
}
