import * as React from 'react';
// ui
import UISecondNavibar, { NaviSelect } from 'taiyaq-ui/src/web2/secondNavibar';
// router
import { RouteComponentProps, withRouter } from 'react-router-dom';

type Props = Readonly<RouteComponentProps<{}>>;

export class SecondNavibar extends React.Component<Props> {
  constructor(props: Props) {
    super(props);
    this.state = {
      toNaviSelect: NaviSelect.Unknown,
      toSearchQuery: undefined,
    };
  }
  handleSelect = (toNaviSelect: NaviSelect) => {
    switch (toNaviSelect) {
      case NaviSelect.All: this.props.history.push('/'); break;  
      case NaviSelect.Like: this.props.history.push('/main'); break;
      case NaviSelect.Mine: this.props.history.push('/mine'); break;
      default: return null;
    }
  }
  handleSearch = (toSearchQuery: string) => {
    this.props.history.push(`/search?query=${encodeURIComponent(toSearchQuery)}`);
  }
  render() {

    const { props } = this;
    let naviSelectByURL: NaviSelect;
    switch (props.location.pathname) {
      case '/': naviSelectByURL = NaviSelect.All; break;
      case '/main': naviSelectByURL = NaviSelect.Like; break;
      case '/mine': naviSelectByURL = NaviSelect.Mine; break;
      default: naviSelectByURL = NaviSelect.Unknown; break;
    }
    
    // 規定のURL以外は非表示
    if (naviSelectByURL === NaviSelect.Unknown) {
      return null;
    }

    return (
      <UISecondNavibar
        naviSelect={naviSelectByURL}
        onSelect={(i) => this.handleSelect(i)}
        onSearch={this.handleSearch}
      />
    );
  }
}

export default withRouter(SecondNavibar);