import { Record, List } from 'immutable';
import { TagCollection } from 'taiyaq-web-api';

interface TopTag {
  name: string;
  useCount: number;
}
interface TopTagsInterface {
  list: List<TopTag>;
}

const TopTagsRecord = Record(<TopTagsInterface> {
  list: List()
});

export default class TopTags extends TopTagsRecord implements TopTagsInterface {
  list: List<TopTag>;
  setTagList(tags: TagCollection): TopTags {
    
    return <TopTags> this.withMutations((rankTags: TopTags) => {
      rankTags.list = rankTags.list.clear();
      tags.forEach(t => {
        rankTags.list = rankTags.list.push({ name: t.name, useCount: t.useCount });
        return;
      });
    });
  }
}