import * as React from "react";

export enum NaviSelect {
  Unknown,
  All,
  Like,
  Mine
}

export interface SecondNavibarProps {
  naviSelect: NaviSelect;
  onSelect: (select: NaviSelect) => void;
  onSearch: (search: string) => void;
}

export interface SecondNavibarState {
  useIME: boolean;
}
export default class SecondNavibar extends React.Component<
  SecondNavibarProps,
  SecondNavibarState
> {
  constructor(props: SecondNavibarProps) {
    super(props);
    this.state = {
      useIME: false
    };
  }

  handleKeyDwon = (e: React.KeyboardEvent<HTMLInputElement>) => {
    const input = e.target as HTMLInputElement;
    const { useIME } = this.state;
    const { onSearch } = this.props;
    if (e.keyCode === 13 && useIME === false) {
      onSearch(input.value);
      input.value = "";
    }
  };
  handleIME = (useIME: boolean) => {
    // console.log('handleIME ' + useIME);
    this.setState({ useIME });
  };
  render() {
    const { naviSelect, onSelect } = this.props;
    return (
      <nav className="navbar is-white is-hidden-mobile ">
        <div className="container">
          <div className="navbar-menu">
            <div className="navbar-start">
              <a
                className={`navbar-item ${naviSelect === NaviSelect.All &&
                  "is-active"} `}
                onClick={() => onSelect(NaviSelect.All)}
              >
                全ての翻訳
              </a>
              <a
                className={`navbar-item ${naviSelect === NaviSelect.Like &&
                  "is-active"} `}
                onClick={() => onSelect(NaviSelect.Like)}
              >
                評価した翻訳
              </a>
              <a
                className={`navbar-item ${naviSelect === NaviSelect.Mine &&
                  "is-active"} `}
                onClick={() => onSelect(NaviSelect.Mine)}
              >
                作成した翻訳
              </a>
            </div>
            <div className="navbar-end">
              <div className="navbar-item">
                <input
                  className="input"
                  type="text"
                  placeholder="検索キーワード"
                  onKeyDown={this.handleKeyDwon}
                  onCompositionUpdate={e => {
                    this.handleIME(true);
                  }}
                  onCompositionStart={e => {
                    this.handleIME(true);
                  }}
                  onCompositionEnd={e => {
                    this.handleIME(false);
                  }}
                />
              </div>
            </div>
          </div>
        </div>
      </nav>
    );
  }
}
