import * as actions from "../../../actions";
import { ActionDispatcher as FeedsActionDispatcher } from "../mainFeed/index";

// UI
import Mine, { Props } from "../mainFeed/mainFeed";

// import { withRouter } from 'react-router-dom';

export class ActionDispatcher extends FeedsActionDispatcher {
  async loadData(useNextCursor?: boolean) {
    this.dispatch(actions.loadFeeds.started(undefined));

    const option = await this.getFetchOption();
    const lang = "ja"; //navigator.language;
    const params = {
      nextCursor: useNextCursor ? this.state.feeds.nextCursor : undefined,
      tag: undefined,
      url: undefined,
      lang
    };
    let contents = await this.contentApi.contentMine(params, option);

    const autherIds = contents.contents.map(c => c.autherGoogleID);
    const nonExistAutherIds = this.notExistAccounts(autherIds);

    // account取得処理
    await this.getAccounts(nonExistAutherIds);

    if (contents.contents) {
      contents.contents.forEach(c => {
        this.dispatch(actions.setContentTiny(c));
      });

      this.dispatch(
        actions.loadFeeds.done({ params: undefined, result: contents })
      );
    }
  }
}

