import { connect } from 'react-redux';
// import * as api from 'taiyaq-web-api';
import * as reducers from '../../../reducers';
import * as actions from '../../../actions';
import { ActionDispatcherBase } from '../../common';
// UI
import MyAccount from './myAccount';
import * as resizeImage from 'resize-image';

function strToImage(str: string): Promise<HTMLImageElement> {
    return new Promise(resolve => {
        let img = new Image();
        img.src = str;
        img.onload = () => {
            resolve(img);
        };
    });
}
export class ActionDispatcher extends ActionDispatcherBase {

    changeImage = (component: MyAccount) => async (instr: string) => {
        console.log('in changeImage ' + instr);
        const img = await strToImage(instr);
        let canvas = resizeImage.resize2Canvas(img, 64, 64);
        if (canvas.height !== 64 || canvas.width !== 64) {
            // alert('正方形サイズの画像を指定して下さい');
            component.setState({
                errMessages: {
                    file: '正方形サイズの画像を指定して下さい',
                }
            });
            // console.log(canvus);
            return;
        }

        let data = resizeImage.resize(canvas, 64, 64);
        component.setState({
            base64image: data,
            errMessages: {
                file: '',
            }
        });
    }

    onSave = (component: MyAccount) => async () => {
        const option = await this.getFetchOption();
        let { newName, base64image } = component.state;
        if (base64image) {
            base64image = base64image.substring('data:image/png;base64,'.length);
        }
        const params = {
            payload: {
                name: newName,
                image: base64image,
            }
        };

        try {
            const account = await this.accountApi.accountUpdateMe(params, option);
            this.dispatch(actions.loadMyInfo.done({ params: undefined, result: account }));
            component.setState({ redirectURL: '/' });
        } catch {
            component.setState({
                errMessages: {
                    name: 'ユーザ名は３文字以上20文字以下の英数字です。'
                }
            });
        }
        
    }
    onReset = (component: MyAccount) => () => {
        component.setState({
            base64image: '',
            newName: '',
        });
    }
}

export default connect(
    (state: reducers.State) => ({ state }),
    (dispatch) => ({ dispatch }),
    ({ state }, { dispatch }, ownProps) => ({
        login: state.login,
        actions: new ActionDispatcher(dispatch, state)
    })
)(MyAccount);
