import * as React from "react";
import { Link } from "react-router-dom";
import SimpleDivFactory from "./helpers/simpleDivFactory";

export const Articles = SimpleDivFactory("box content ");

export interface ArticleReadMoreProps {
  isLoading?: boolean;
  onClick?: () => void;
}

export const ArticleReadMore = ({
  onClick,
  isLoading
}: ArticleReadMoreProps) => (
  <button
    className={`button is-fullwidth  ${isLoading && "is-loading"}`}
    style={{ borderTop: "0px" }}
    onClick={() => onClick && !isLoading && onClick()}
  >
    Read More
  </button>
);

interface OnClickProps {
  onClick?: () => void;
}
const Tag = ({ tag, onClick }: { tag: string } & OnClickProps) => (
  <a
    className="tag is-primary "
    style={{ marginLeft: "5px" }}
    onClick={onClick}
  >
    {tag}
  </a>
);

const URL = ({ url }: { url: string } & OnClickProps) => (
  <div
    className="field is-grouped is-grouped-multiline is-hidden-mobile"
    style={{ float: "right" }}
  >
    <div className="control">
      <div className="tags has-addons">
        <span className="tag is-dark is-small">URL</span>
        <span className="tag is-small">{url}</span>
      </div>
    </div>
  </div>
);

const Like = ({ like }: { like: number }) => (
  <span style={{ float: "right" }}>
    <i className="fa far fa-thumbs-up" /> {like}
  </span>
);

export interface ArticleProps {
  id: string;
  imgURL: string;
  tags: string[];
  url: string;
  title: string;
  like: number;
  modifiedMessages: string;
  auther: string;
  onClickTitle?: () => void;
  onClickTag?: (tagName: string) => void;
  onClickAuther?: () => void;
}

const Article = ({
  id,
  imgURL,
  tags,
  url,
  title,
  like,
  modifiedMessages,
  auther,
  onClickTitle,
  onClickTag,
  onClickAuther
}: ArticleProps) => (
  <article
    className="post"
    style={{
      margin: "0.7rem",
      paddingBottom: "1rem",
      borderBottom: "1px solid #E6EAEE"
    }}
  >
    <URL url={url} />
    <h4>
      <Link to={`/contents/${id}`} onClick={onClickTitle}>
        {title}
      </Link>
    </h4>

    <Like like={like} />

    <div className="media">
      <div className="media-left">
        <p className="image is-32x32">
          <img src={imgURL} />
        </p>
      </div>
      <div className="media-content">
        <div className="content">
          <p
            style={{
              fontSize: "14px",
              lineHeight: "2.3",
              fontWeight: 500,
              color: "8F99A3",
              marginBottom: "0px"
            }}
          >
            <a onClick={onClickAuther}>{auther}</a>
            &nbsp; &nbsp; &nbsp;
            {modifiedMessages}
            &nbsp;
            {tags.map(tag => (
              <Tag
                key={tag}
                tag={tag}
                onClick={onClickTag && (() => onClickTag(tag))}
              />
            ))}
            &nbsp;
          </p>
        </div>
      </div>
    </div>
  </article>
);

export default Article;
