
import * as React from 'react';
// ui
import UserInfo from 'taiyaq-ui/src/web2/userInfo';

// actions 
import { ActionDispatcher } from './index';

// api
import * as api from 'taiyaq-web-api';

// models
import Accounts from '../../../models/accounts';
import ContentDetail from '../../../containers/primary/contentDetail/model';

interface Props {
  contentID: string;
  contentDetail: ContentDetail;
  accounts: Accounts;
  actions: ActionDispatcher;
}
interface State {
  account?: api.Account;
  image?: string;
}
export default class MyInfo extends React.Component<Props, State> {
  handleState = () => {
    // 必要な情報が取得済みなら何もしない
    const { account, image } = this.state;
    if (account && image) {
      return;
    }

    const { accounts, contentDetail, contentID } = this.props;

    if (accounts === undefined) {
      return;
    }

    let c: api.Content | api.ContentTiny | undefined = contentDetail.getContent(contentID);
    if (c === undefined) {
      // console.log('getContent return nil ');
      c = contentDetail.getContentTiny(contentID);
    }
    
    if (c === undefined) {
      // console.log('getContentTiny return nil ');
      return;
    }
    
    const a = accounts.getAccount(c.autherGoogleID);
    if (a) {
      this.setState({
        account: a,
        image: accounts.getImage(a.googleUserID),
      });
    } else {
      // 取得処理
      this.props.actions.getAccounts([c.autherGoogleID]);
    }
  }
  constructor(props: Props) {
    super(props);
    this.state = {};
  }
  componentDidUpdate() {
    this.handleState();
  }
  render() {
    // const { account, image } = this.props;
    const { account, image } = this.state;
    if (account === undefined || image === undefined) {
      return null;
    }
    return (
      <UserInfo
        imgURL={image || ''}
        name={account.name}
        likesCount={account.point}
        translationsCount={account.countOfContents}
        onClickLikesCount={() => false}
        onClickTranslations={() => false}
        onClickUser={() => false}
      />
    );
  }
}