import * as React from 'react';

import UIMyAccount from 'taiyaq-ui/src/web/myAccount';
import { ActionDispatcher } from './index';

// models
import Login from '../../../models/login';

// routing
import { Redirect } from 'react-router-dom';

export interface Props {
  login: Login;
  actions: ActionDispatcher;
}

export interface State {
  base64image: string;
  newName: string;
  redirectURL?: string;
  errMessages?: {
    file?: string;
    name?: string;
  };
}
class MyAccount extends React.Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = {
      base64image: '',
      newName: '',
    };
  }

  render() {
    const { redirectURL, errMessages } = this.state;
    const { login, actions } = this.props;

    if (redirectURL) {
      return <Redirect to="/" />;
    }

    let dissableButton = this.state.newName === '' && this.state.base64image === '';

    let name = this.state.newName;
    if (name === '') {
      name = login.name;
    }

    let image = this.state.base64image;
    if (image === '') {
      image = login.image || '';
    }

    return (
        <UIMyAccount
          avatar={image}
          name={name}
          onChageFile={actions.changeImage(this)}
          onChangeName={newName => this.setState({ newName })}
          onSave={actions.onSave(this)}
          onReset={actions.onReset(this)}
          errMessages={errMessages}
          disableButton={dissableButton}
        />
    );
  }
}

export default MyAccount;