import * as React from 'react';
import { RouteComponentProps } from 'react-router-dom';

// UI
import { Articles, ArticleReadMore } from 'taiyaq-ui/src/web2/article';
// import Article, { Articles, ArticleReadMore } from '../../web2/article';
import TagInfo from 'taiyaq-ui/src/web2/tagInfo';

import { ActionDispatcher } from './index';

// import FeedTabs from '../../containers/feedTabs';

import FeedBase from '../../common/feedBase';

// models
import Feeds from '../../../models/feeds';
import Tags from '../../../models/tags';
import Accounts from '../../../models/accounts';

export interface Props extends RouteComponentProps<{ tagName: string }> {
  feeds: Feeds;
  tags: Tags;
  accounts: Accounts;
  actions: ActionDispatcher;
}

export default class TagFeeds<T extends Props> extends FeedBase<T> {
  render() {
    const { feeds, tags, history } = this.props;
    const tagName = decodeURIComponent(this.props.match.params.tagName);
    
    const tag = tags.list.get(tagName);
    
    return (
      <div>
        <TagInfo name={tagName} count={tag && tag.useCount || feeds.ContentTinyCollection.length} />
        <Articles>
        {
          feeds.ContentTinyCollection().map(
            this.makeFeed({
              onClickTitle: contentID => history.push(`/contents/${contentID}`),
              onClickTag: t => history.push(`/tags/${encodeURIComponent(t)}`),
            })
        )
      }
        {
          feeds.ContentTinyCollection().length >= 10 && <ArticleReadMore
            isLoading={feeds.isLoading}
            onClick={() => this.props.actions.loadTagFeeds(tagName, true)}
          />
        }
        </Articles>
      </div>
    );
  }
  componentWillReceiveProps(nextProps: Readonly<T>) {

    const current = this.props.match.params.tagName;
    const next = nextProps.match.params.tagName;
    if (current !== next && next !== '') {
      this.props.actions.resetTagFeeds(next);
    }
  }
  constructor(props: T) {
    super(props);
    const tagName = decodeURIComponent(props.match.params.tagName);
    this.props.actions.resetTagFeeds(tagName);
  }
}
