import { Record, Map } from 'immutable';
import { Tag } from 'taiyaq-web-api';

type TagName = string;

interface TagsInterface {
    list: Map<TagName, Tag>;
}

const TagsRecord = Record(<TagsInterface> {
    list: Map(),
});

export default class Tags extends TagsRecord implements TagsInterface {
    list: Map<TagName, Tag>;
    setTag(tag: Tag): Tags {
        return <Tags> this.setIn(['list', tag.name], tag);
    }
    getTag(name: string): Tag {
        return <Tag> this.list.get(name);
    }
}