import * as reducers from "../../../reducers";
import * as actions from "../../../actions";
import { ActionDispatcherBase } from "../../common";
// UI
import Search from "./search";

// utility
import { uniq } from "lodash";

// Router
import { RouteComponentProps } from "react-router-dom";
import * as H from "history";

function searchToObj(search: string): Object {
  let arg = new Object();
  let pair = search.substring(1).split("&");
  for (var i = 0; pair[i]; i++) {
    const kv = pair[i].split("=");
    arg[kv[0]] = decodeURIComponent(kv[1]);
  }
  return arg;
}

interface SearchObj {
  query?: string;
  nextCursor?: string;
}
export class ActionDispatcher extends ActionDispatcherBase {
  search(location: H.Location) {
    let query = "";
    let nextCursor = "";
    if (location.search) {
      // search = location.search;
      const obj = searchToObj(location.search) as SearchObj;
      if (obj.query) {
        query = obj.query;
      }
      if (obj.nextCursor) {
        nextCursor = obj.nextCursor;
      }
    }
    return { query, nextCursor };
  }
  notExistAccounts(accountIDs: string[]): string[] {
    const existAccounts = this.state.accounts.accounts;
    const notExistIDs = uniq(accountIDs).filter(id => !existAccounts.has(id));
    return notExistIDs;
  }

  // async getAccounts(accountIds: string[]) {
  //     const option = await this.getFetchOption();
  //     if (accountIds.length > 0) {
  //         this.dispatch(actions.loadAccounts.started({ ids: accountIds }));

  //         let accounts = await this.accountApi.accountList({ ids: accountIds }, option);

  //         this.dispatch(actions.loadAccounts.done({ params: { ids: accountIds }, result: accounts }));
  //     }
  // }

  async resetData(location: H.Location) {
    this.dispatch(actions.resetFeeds());
    await this.loadData(location, false);
  }
  async loadData(location: H.Location, useNextCursor?: boolean) {
    this.dispatch(actions.loadFeeds.started(undefined));

    const option = await this.getFetchOption();
    const { query } = this.search(location);
    const params = {
      nextCursor: useNextCursor ? this.state.feeds.nextCursor : undefined,
      q: query
    };
    let contents = await this.contentApi.contentSearch(params, option);

    const autherIds = contents.contents.map(c => c.autherGoogleID);
    const nonExistAutherIds = this.notExistAccounts(autherIds);

    // account取得処理
    await this.getAccounts(nonExistAutherIds);

    if (contents.contents) {
      contents.contents.forEach(c => {
        this.dispatch(actions.setContentTiny(c));
      });

      this.dispatch(
        actions.loadFeeds.done({ params: undefined, result: contents })
      );
    }
  }
}

export default connect(
  (state: reducers.State) => ({ state }),
  dispatch => ({ dispatch }),
  ({ state }, { dispatch }, ownProps: RouteComponentProps<{}>) => ({
    ...ownProps,
    location: ownProps.location,
    feeds: state.feeds,
    accounts: state.accounts,
    actions: new ActionDispatcher(dispatch, state)
  })
)(Search);
