import * as React from "react";

export interface OnClick {
  (): void;
}
export interface UserInfoProps {
  imgURL: string;
  name: string;
  likesCount: number;
  translationsCount: number;
  onClickUser: OnClick;
  onClickTranslations: OnClick;
  onClickLikesCount: OnClick;
  onClickModify?: OnClick;
}
const UserInfo = ({
  imgURL,
  name,
  likesCount,
  translationsCount,
  onClickUser,
  onClickTranslations,
  onClickLikesCount,
  onClickModify
}: UserInfoProps) => (
  <div className="box">
    <figure className="content image is-48x48">
      <img src={imgURL} />
    </figure>
    <div className="content">
      <ul
        style={{
          listStyleType: "None",
          marginLeft: "0px",
          fontSize: "14px"
        }}
      >
        <li>
          <a onClick={onClickUser}>{name}</a>
        </li>
        <li>
          <a onClick={onClickTranslations}>{translationsCount}</a> 翻訳
        </li>
        <li>
          <a onClick={onClickLikesCount}>{likesCount}</a> 評価
        </li>
      </ul>
      {onClickModify && (
        <button className="button is-fullwidth" onClick={onClickModify}>
          変更
        </button>
      )}
    </div>
  </div>
);

export default UserInfo;
