import * as React from "react";

const RankedTag = ({
  name,
  count,
  onClick
}: {
  name: string;
  count: number;
  onClick: (name: string) => void;
}) => (
  <a
    className="tags has-addons "
    style={{ paddingTop: "0px" }}
    onClick={() => onClick(name)}
  >
    <span className="tag is-primary ">{name}</span>
    <span className="tag is-dark ">{count}</span>
  </a>
);

export interface TopTagsItem {
  name: string;
  count: number;
}
export interface TopTagsProps {
  items: TopTagsItem[];
  onSelectTag: (tagName: string) => void;
}

const TopTags = ({ items, onSelectTag }: TopTagsProps) => (
  <aside
    className="menu"
    // style={{ paddingTop: '3rem' }}
  >
    <p className="menu-label">Top Tags</p>
    <ul className="menu-list">
      {items.map(item => (
        <li key={item.name}>
          <RankedTag
            name={item.name}
            count={item.count}
            onClick={onSelectTag}
          />
        </li>
      ))}
    </ul>
  </aside>
);

export default TopTags;
