import { Dispatch } from "redux";
import * as reducers from "../../reducers";
import * as ReactRedux from "react-redux";
import { isType, AnyAction } from "typescript-fsa";
import { ExtensionIDs } from "../../../settings";
// actions
import * as actions from "../../actions";
import * as messageActions from "../message/actions";
// api
import * as api from "taiyaq-web-api";

export let runOptions = { fetch, baseURL: location.origin + "/api/v1" };

if (process.env.NODE_ENV === "development") {
  runOptions = { fetch, baseURL: "http://localhost:9089" + "/api/v1" };
}

export class ActionDispatcherBase {
  protected accountApi = new api.AccountApi(
    runOptions.fetch,
    runOptions.baseURL
  );
  protected contentApi = new api.ContentApi(
    runOptions.fetch,
    runOptions.baseURL
  );
  protected tagApi = new api.TagApi(runOptions.fetch, runOptions.baseURL);

  constructor(
    protected dispatch: Dispatch<{}>,
    protected state: reducers.State
  ) {}

  getFetchOption = async () => {
    try {
      const option = this.state.login.fetchOptions();
      if (option) {
        return option;
      }
      return {};
    } catch (e) {
      // console.warn(e);
    }
    return {};
  };

  sendMessage = async (extensionID: string, action: AnyAction) => {
    return new Promise<AnyAction | undefined>(resolve => {
      chrome.runtime.sendMessage(extensionID, action, (response: AnyAction) => {
        resolve(response);
      });
    });
  };

  showMessage = async (txt: string) => {
    this.dispatch(messageActions.setMessage({ txt }));
  };
  showErrorMessage = async (txtOrErr: string | Error) => {
    if (txtOrErr instanceof Error) {
      this.dispatch(messageActions.setErrorMessage({ txt: txtOrErr.message }));
      return;
    }
    this.dispatch(messageActions.setErrorMessage({ txt: txtOrErr }));
  };

  existTaiyaqExtension = async () => {
    for (const extensionID of ExtensionIDs) {
      const resp = await this.sendMessage(
        extensionID,
        actions.existTaiyaqExtension()
      );

      if (resp && isType(resp, actions.isExistTaiyaqExtension)) {
        return true;
      }
    }
    return false;
  };

  getAccounts = async (accountIds: string[]) => {
    const option = await this.getFetchOption();
    if (accountIds.length > 0) {
      this.dispatch(actions.loadAccounts.started({ ids: accountIds }));

      let accounts = await this.accountApi.accountList(
        { ids: accountIds },
        option
      );

      this.dispatch(
        actions.loadAccounts.done({
          params: { ids: accountIds },
          result: accounts
        })
      );
    }
  };
}

interface MergeProps<TProps extends { actions: ActionDispatcherBase }> {
  (
    state: reducers.State,
    dispatch: Dispatch<AnyAction>,
    ownProps: TProps
  ): TProps;
}

export function connect<TProps extends { actions: ActionDispatcherBase }>(
  ActionDispatcher: typeof ActionDispatcherBase,
  mergeProps: MergeProps<TProps>
): ReactRedux.InferableComponentEnhancer<TProps> {
  return ReactRedux.connect(
    (state: reducers.State) => ({ state }),
    (dispatch: Dispatch<AnyAction>) => ({ dispatch }),
    ({ state }, { dispatch }, ownProps: TProps) => {
      const props = mergeProps(state, dispatch, ownProps);
      return Object.assign({}, props, {
        actions: new ActionDispatcher(dispatch, state)
      });
    }
  );
}
