import * as api from 'taiyaq-web-api';
import * as actions from '../../actions';
import { ActionDispatcherBase, runOptions, connect } from '../common';
// UI
import Navi, { Props } from './navi';

export class ActionDispatcher extends ActionDispatcherBase {
  async loadLoginInfo() {

    this.dispatch(actions.loadMyInfo.started(undefined));

    let option: Object | undefined;
    try {
      option = this.state.login.fetchOptions();
    } catch (e) {
      return;
    }

    let result = await api.AccountApiFp
      .accountShowMe(option)(runOptions.fetch, runOptions.baseURL)
      .catch(err => {
        console.log('err', err);
        return null;
      });
    if (result) {
      this.dispatch(actions.loadMyInfo.done({ params: undefined, result }));
    }
  }
  logout = async () => {
    this.dispatch(actions.logout());
  }
  login = () => {
    let currentURL = location.href;
    location.href = `/login?next_url=${currentURL}`;
  }
}

export default connect<Props>(
  ActionDispatcher,
  (state, dispatch, ownProps) => ({
    ...ownProps,
    login: state.login,
  })
)(Navi);