
import * as React from 'react';
// ui
import UIMessage from 'taiyaq-ui/src/web2/message';

// actions 
import { ActionDispatcher } from './index';

// models
import MessageModel from './model';

// router
// import { RouteComponentProps } from 'react-router-dom';

export interface Props {
  actions: ActionDispatcher;
  message: MessageModel;
}
interface State {
  timeOutSec: number;
}
export default class Message extends React.Component<Props, State> {
  constructor(props: Props) {
    super(props);
    const { date } = props.message;
    this.state = {
      timeOutSec: this.diffTime(date),
    };
  }
  diffTime = (before: Date) => {
    const now = new Date();
    return now.getTime() - before.getTime();
  }

  handleIntervaltime = () => {
    const timeOutSec = this.diffTime(this.props.message.date);
    if (timeOutSec > 4500) {
      return;
    }
    this.setState({ timeOutSec });
  }
  componentDidMount() {
    // TODO この対応は良いのだろうか？ 常にループが回ってるわけですが
    setInterval(this.handleIntervaltime, 200);
  }

  render() {
    const { message } = this.props;
    const { timeOutSec } = this.state;
    if (timeOutSec > 4000) {
      return null;
    }
    return (
      <UIMessage
        txt={message.txt}
        isDanger={message.isDanger}
        isTimeout={timeOutSec > 3000}
      />
    );
  }
}