import * as React from "react";
import FeedBase from "../../common/feedBase";

// UI
import { ArticleReadMore, Articles } from "taiyaq-ui/src/web2/article";
// import Login from '../../models/login';
import { ActionDispatcher } from "./index";
// models
import Feeds from "../../../models/feeds";
import Accounts from "../../../models/accounts";
// router
import { RouteComponentProps } from "react-router-dom";

export interface Props extends RouteComponentProps<{}> {
  feeds: Feeds;
  accounts: Accounts;
  actions: ActionDispatcher;
}

export default class MainFeed<T extends Props> extends FeedBase<T> {
  render() {
    const { feeds, history } = this.props;

    return (
      <Articles>
        {feeds.ContentTinyCollection().map(
          this.makeFeed({
            onClickTitle: contentID => history.push(`/contents/${contentID}`),
            onClickTag: tag => history.push(`/tags/${encodeURIComponent(tag)}`)
          })
        )}
        {feeds.ContentTinyCollection().length >= 10 && (
          <ArticleReadMore
            isLoading={feeds.isLoading}
            onClick={() => this.props.actions.loadData(true)}
          />
        )}
      </Articles>
    );
  }
  constructor(props: T) {
    super(props);
    this.props.actions.resetData();
  }
}
