import { connect } from "react-redux";
// import * as api from 'taiyaq-web-api';

import * as reducers from "../../../reducers";
import * as actions from "../../../actions";

// import { ActionDispatcherBase } from '../common';
import { ActionDispatcher as FeedsActionDispatcher } from "../mainFeed/index";

// UI
import TagFeeds, { Props } from "./tags";
// import { withRouter } from 'react-router-dom';

export class ActionDispatcher extends FeedsActionDispatcher {
  async loadTagFeeds(tagName: string, useNextCursor?: boolean) {
    this.dispatch(actions.loadFeeds.started(undefined));
    tagName = decodeURIComponent(tagName);

    const option = await this.getFetchOption();
    const lang = "ja"; // navigator.language;
    const params = {
      nextCursor: useNextCursor ? this.state.feeds.nextCursor : undefined,
      tag: tagName,
      url: undefined,
      lang
    };
    let contents = await this.contentApi.contentAll(params, option);

    const autherIds = contents.contents.map(c => c.autherGoogleID);
    const nonExistAutherIds = this.notExistAccounts(autherIds);

    // account取得処理
    await this.getAccounts(nonExistAutherIds);

    if (contents.contents) {
      contents.contents.forEach(c => {
        this.dispatch(actions.setContentTiny(c));
      });

      this.dispatch(
        actions.loadFeeds.done({ params: undefined, result: contents })
      );
    }
    // tag情報の取得
    try {
      let tag = await this.tagApi.tagShow({
        name: encodeURIComponent(tagName)
      });
      this.dispatch(actions.setTag(tag));
    } catch (e) {
      console.error("error ", e);
    }
  }

  async resetTagFeeds(tagName: string) {
    this.dispatch(actions.resetFeeds());
    await this.loadTagFeeds(tagName, false);
  }
}

export default connect(
  (state: reducers.State) => ({ state }),
  dispatch => ({ dispatch }),
  ({ state }, { dispatch }, ownProps: Props) => ({
    ...ownProps,
    tags: state.tags,
    feeds: state.feeds,
    accounts: state.accounts,
    actions: new ActionDispatcher(dispatch, state)
  })
)(TagFeeds);
