
import * as React from 'react';
// ui
import UserInfo from 'taiyaq-ui/src/web2/userInfo';

// actions 
import { ActionDispatcher } from './index';

// models
import Login from '../../../models/login';

// router
import { RouteComponentProps } from 'react-router-dom';

interface Props extends RouteComponentProps<{}> {
  actions: ActionDispatcher;
  login: Login;
}
export default class MyInfo extends React.Component<Props, {}> {
  render() {
    const isLogin = this.props.login.isLogin();
    if (!isLogin) {
      return null;
    }

    const { name, image, countOfContents, point } = this.props.login;
    return (
      <UserInfo
        imgURL={image || ''}
        name={name}
        likesCount={point}
        translationsCount={countOfContents}
        onClickLikesCount={() => false}
        onClickTranslations={() => false}
        onClickUser={() => false}
        onClickModify={() => this.props.history.push('/my_account')}
      />
    );
  }
}