import { Record, Map } from 'immutable';
import { Account } from 'taiyaq-web-api';

type GoogleUserID = string;
type Base64Image = string;

interface AccountsInterface {
    images: Map<GoogleUserID, Base64Image>;
    accounts: Map<GoogleUserID, Account>;
}

const AccountsRecord = Record(<AccountsInterface> {
    images: Map(),
    accounts: Map(),
});

export default class Accounts extends AccountsRecord implements AccountsInterface {
    images: Map<GoogleUserID, Base64Image>;
    accounts: Map<GoogleUserID, Account>;

    getImage(googleUserID: GoogleUserID): string {
        return this.images.get(googleUserID);
    }
    getAccount(googleUserID: GoogleUserID): Account {
        return this.accounts.get(googleUserID);
    }
    setAccounts(list: Account[]): Accounts {
        return <Accounts> this.withMutations((accounts: Accounts) => {
            list.forEach(a => {
                accounts.images = accounts.images.set(a.googleUserID, `data:image/png;base64,${a.image}`);
                delete a.image;
                accounts.accounts = accounts.accounts.set(a.googleUserID, a); 
            });
            return accounts;
        });
    }
}