export default connect<Props>(
  ActionDispatcher,
  (state, dispatch, ownProps) => ({
    ...ownProps,
    feeds: state.feeds,
    accounts: state.accounts,
    actions: new ActionDispatcher(dispatch, state)
  })
)(MainFeed);
