import * as React from "react";

const Tag = ({ name }: { name: string }) => {
  return (
    <div
      className="tag is-black"
      style={{
        position: "relative",
        top: "18px",
        left: "1px"
      }}
    >
      {name}
    </div>
  );
};

interface BoxProps {
  tagName: string;
  content: React.ReactNode;
}
const Box = ({ tagName, content }: BoxProps) => {
  return (
    <div>
      <Tag name={tagName} />
      <div
        className="box"
        style={{
          padding: "10px",
          margin: "10px",
          marginBottom: "1px"
        }}
      >
        {content}
      </div>
    </div>
  );
};

const TranslationCell = ({
  base,
  translate
}: {
  base: string;
  translate: String;
}) => {
  return (
    <article className="media">
      <div className="media-content">
        <Box tagName="翻訳元" content={base} />
        <Box tagName="翻訳" content={translate} />
      </div>
    </article>
  );
};

export default TranslationCell;
