// import * as api from 'taiyaq-web-api';
import { reducerWithInitialState } from 'typescript-fsa-reducers';

// actions
import * as actions from './actions';

// models
import TopTags from './model';

const topTags = reducerWithInitialState(new TopTags())
    .case(actions.setTopTags, (state, payload) => state.setTagList(payload))
;

export default topTags;