import { Record } from 'immutable';

interface MessageInterface {
    txt: string;
    isDanger: boolean;
    date: Date;
}

const MessageRecord = Record(<MessageInterface> {
    txt: '',
    isDanger: false,
    date: new Date('1999/9/9')
});

export default class Message extends MessageRecord implements MessageInterface {
    txt: string;
    isDanger: boolean;
    date: Date;
    setMessage(txt: string, isDanger: boolean) {
        return <Message> this.withMutations( (message: Message) => {
            message.txt = txt;
            message.isDanger = isDanger;
            message.date = new Date();
            return message;
        });
    }
}