
import * as React from 'react';
// ui
import UITopTags from 'taiyaq-ui/src/web2/topTags';

// actions 
import { ActionDispatcher } from './index';

// models
import TopTagsModel from './model';

import { RouteComponentProps } from 'react-router-dom';

interface Props extends RouteComponentProps<{}> {
  actions: ActionDispatcher;
  topTags: TopTagsModel;
}

// interface State {
//   selectTag?: string;
// }
export default class TopTags extends React.Component<Props> {
  constructor(props: Props) {
    super(props);
    this.state = { selectTag: undefined };
    this.props.actions.loadData();
  }
  // handleRedirect = () => {
  //   const { selectTag } = this.state;
  //   if (selectTag === undefined) {
  //     return null;
  //   }
  //   return <Redirect to={`/tags/${encodeURIComponent(selectTag)}`} />;
  // }
  render() {
    // const redirect = this.handleRedirect();
    // if (redirect !== null) {
    //   return redirect;
    // }

    const { topTags } = this.props;
    const items = topTags.list.toArray().map(t => ({ name: t.name, count: t.useCount }));
    return (
      <UITopTags
        items={items}
        onSelectTag={(t) => this.props.history.push(`/tags/${encodeURIComponent(t)}`)}
      />
    );
  }
}