import { reducerWithInitialState } from 'typescript-fsa-reducers';

import { combineReducers } from 'redux-immutable';
import * as Immutable from 'immutable';

// actions
import * as actions from '../actions';

// models
import Login from '../models/login';
import Feeds from '../models/feeds';
import Accounts from '../models/accounts';
import Tags from '../models/tags';

// models local
import TopTagsModel from '../containers/secondary/topTags/model';
import ContentDetailModel from '../containers/primary/contentDetail/model';
import Message from '../containers/message/model';

// reducers local
import contentDetail from '../containers/primary/contentDetail/reducer';
import topTags from '../containers/secondary/topTags/reducer';
import message from '../containers/message/reducer';

export interface State {
    login: Login;
    feeds: Feeds;
    accounts: Accounts;
    tags: Tags;
    topTags: TopTagsModel;
    contentDetail: ContentDetailModel;
    message: Message;
}

// reducers global
export const initStateRecord = Immutable.Record(<State> {
    login: new Login(),
    feeds: new Feeds(),
    accounts: new Accounts(),
    tags: new Tags(),
    topTags: new TopTagsModel(),
    contentDetail: new ContentDetailModel(),
    message: new Message(),
});

const login = reducerWithInitialState(new Login())
    .case(actions.loadMyInfo.done, (state, payload) => (state.setMyAccount(payload.result)))
    .case(actions.logout, (state, payload) => (state.logout()))
    ;

const feeds = reducerWithInitialState(new Feeds())
    .case(actions.loadFeeds.started, state => state.setLoading(true))
    .case(actions.loadFeeds.done, (state, payload) => (state.setList(payload.result)))
    .case(actions.resetFeeds, state => (new Feeds()))
    ;

const accounts = reducerWithInitialState(new Accounts())
    .case(actions.loadAccounts.done, (state, payload) => state.setAccounts(payload.result))
    ;
const tags = reducerWithInitialState(new Tags())
    .case(actions.setTag, (state, payload) => state.setTag(payload))
    ;

const root = {
    login,
    feeds,
    accounts,
    tags,
    topTags,
    contentDetail,
    message,
};

export default combineReducers(root, initStateRecord);
