import * as React from 'react';

export interface Props extends React.Props<{}> {
  txt?: string;
  isTimeout?: boolean;
  isDanger?: boolean;
  onClick?: () => void;
}

const bestWidth = () => {
  let width = 500;
  if (innerWidth < 700) {
    width = innerWidth;
  }
  return width;
};

const style: React.CSSProperties = {
  position: 'fixed', right: '10px', width: `${bestWidth() - 20}px`, zIndex: 1
};

const Message = (props: Props) => {
  const { txt, isTimeout, isDanger, onClick } = props;
  const basicClass = 'message is-success animated ';
  if (txt && !isTimeout) {
    return (
      <article
        className={basicClass + ' pulse ' + `${isDanger && 'is-danger'}`}
        style={{ ...style }}
        onClick={onClick}
      >
        <div className="message-header">
          <p>{`${isDanger ? 'error' : 'info' }`}</p>
        </div>
        <div className="message-body">
          {txt}
        </div>
      </article>
    );
  }
  if (txt && isTimeout) {
    return (
      <article
        className={basicClass + ` fadeOut ` + `${isDanger && 'is-danger'}`}
        style={{
          pointerEvents: 'none',
          ...style
        }}
      >
        <div className="message-header">
        <p>{`${isDanger ? 'error' : 'info' }`}</p>
        </div>
        <div className="message-body">
          {txt}
        </div>
      </article>
    );
  }
  return null;
};

export default Message;