import { connect } from 'react-redux';
import * as reducers from '../../../reducers';
import { ActionDispatcherBase } from '../../common';
// UI
import TopTags from './topTags';

// actions
import * as TopTagsActions from './actions';
// router
import { withRouter } from 'react-router-dom';

export class ActionDispatcher extends ActionDispatcherBase {
    loadData = async () => {
        const tags = await this.tagApi.tagRank();
        this.dispatch(TopTagsActions.setTopTags(tags.tags));
    }
}

export default withRouter(connect(
    (state: reducers.State) => ({ state }),
    (dispatch) => ({ dispatch }),
    ({ state }, { dispatch }, ownProps) => ({ 
        ...ownProps,
        topTags: state.topTags,
        actions: new ActionDispatcher(dispatch, state),
    })
)(TopTags));
