// import * as api from 'taiyaq-web-api';
import { reducerWithInitialState } from 'typescript-fsa-reducers';

// actions
import * as actions from './actions';

// models
import Message from './model';

const message = reducerWithInitialState(new Message())
    .case(actions.setMessage, (state, payload) => state.setMessage(payload.txt, false))
    .case(actions.setErrorMessage, (state, payload) => state.setMessage(payload.txt, true))
    ;

export default message;