import { Record, OrderedMap } from 'immutable';
import { ContentTiny, Contentlist } from 'taiyaq-web-api';

type ContentID = string;

interface FeedsInterface {
  // list: List<ContentTiny>;
  l: OrderedMap<ContentID, ContentTiny>;
  nextCursor?: string;
  isLoading?: boolean;
}

const FeedsRecord = Record(<FeedsInterface> {
  // list: List<ContentTiny>(),
  l: OrderedMap(),
  nextCursor: undefined,
  isLoading: undefined,
});

export default class Feeds extends FeedsRecord implements FeedsInterface {
  l: OrderedMap<ContentID, ContentTiny>;
  nextCursor?: string;
  isLoading?: boolean;

  setLoading(isLoading: boolean): Feeds {
    return <Feeds> this.setIn(['isLoading'], isLoading);
  }
  ContentTinyCollection(): ContentTiny[] {
    return this.l.toArray();
  }
  getContentTiny(contentID: string): ContentTiny | undefined {
    return this.l.get(contentID, undefined);
  }
setList(list: Contentlist): Feeds {
  return <Feeds> this.withMutations((d) => {
    const feeds = d as Feeds;
    // feeds.list = feeds.list.push(...list.contents);
    list.contents.forEach(c => feeds.l = feeds.l.set(c.id, c));
    feeds.nextCursor = list.nextCursor;
    feeds.isLoading = false;
    return feeds;
  });
}
}