import { Record, Map } from "immutable";
import { Content, ContentTiny } from "taiyaq-web-api";

interface ContentDetailInterface {
  contentMap: Map<string, Content>;
  contentTinyMap: Map<string, ContentTiny>;
  isExistExtension: boolean;
}

const ContentDetailRecord = Record(<ContentDetailInterface>{
  contentMap: Map(),
  contentTinyMap: Map(),
  isExistExtension: false
});

export default class ContentDetail extends ContentDetailRecord
  implements ContentDetailInterface {
  contentMap: Map<string, Content>;
  contentTinyMap: Map<string, ContentTiny>;
  isExistExtension: boolean;

  setContent(content: Content): ContentDetail {
    return <ContentDetail>this.withMutations((c: ContentDetail) => {
      c.contentMap = c.contentMap.set(content.id, content);
    });
  }
  setContentTiny(content: ContentTiny): ContentDetail {
    return <ContentDetail>this.withMutations((c: ContentDetail) => {
      c.contentTinyMap = c.contentTinyMap.set(content.id, content);
      return c;
    });
  }

  setExistExtension(isExist: boolean): ContentDetail {
    return <ContentDetail>this.set("isExistExtension", isExist);
  }
  getContentTiny(id: string): ContentTiny | undefined {
    return this.contentTinyMap.get(id);
  }
  getContent(id: string): Content | undefined {
    return this.contentMap.get(id);
  }
}
