import * as api from 'taiyaq-web-api';
import actionCreatorFactory from 'typescript-fsa';

const actionCreator = actionCreatorFactory();
// jwtを元にして自分のアカント情報の収集
export const loadMyInfo = actionCreator.async<undefined, api.Account>('LOAD_MYINFO');

// feed用のコンテンツの取得
export const loadFeeds = actionCreator.async<undefined, api.Contentlist>('LOAD_FEEDS');
// feedのリセット
export const resetFeeds = actionCreator('RESET_FEEDS');

// accountsの取得
export const loadAccounts = actionCreator.async<{ ids: string[] }, api.AccountCollection>('LOAD_ACCOUNTS');

// tag の設定
export const setTag = actionCreator<api.Tag>('SET_TAG');

// contentの設定
export const setContent = actionCreator<api.Content>('SET_CONTENT');
// content(tiny)の設定
export const setContentTiny = actionCreator<api.ContentTiny>('SET_CONTENT_TINY');

// extensionにコンテンツ情報を送信する //TODO extensionとかぶっている
export const sendContentToExtension = actionCreator<api.Content>('SEND_CONTENT_TO_EXTENSION');
// extesnsionの存在確認 //TODO extensionとかぶっている
export const existTaiyaqExtension = actionCreator('EXIST_TAIYAQ_EXTENSION');
// //TODO extensionとかぶっている
export const isExistTaiyaqExtension = actionCreator('IS_EXIST_TAIYAQ_EXTENSION');

export const logout = actionCreator('LOGOUT');
