import * as React from "react";
import Navibar from "taiyaq-ui/src/web2/navibar";

import Login from "../../models/login";
import { ActionDispatcher } from "./index";
// router
// import { Redirect } from 'react-router-dom';

export interface Props extends React.Props<{}> {
  login: Login;
  actions: ActionDispatcher;
}
export interface State {
  // redirctURL?: string;
}

const menu = [
  {
    title: "Taiyaqについて",
    onAction: () => (location.href = "https://taiyaq.github.io")
  }
];
export default class Navi extends React.Component<Props, State> {
  constructor(props: Props) {
    super(props);
    const { login, actions } = this.props;
    if (login.image === undefined) {
      actions.loadLoginInfo();
    }
    this.state = {
      redirctURL: undefined
    };
  }
  render() {
    const { login, actions } = this.props;
    // const { redirctURL } = this.state;
    // if (redirctURL) {
    //   return <Redirect to={redirctURL} />;
    // }
    const isLogin = login.isLogin();
    return (
      <Navibar
        imgURL={require("./logo.svg")}
        actions={menu}
        onLogin={actions.login}
        onLogout={actions.logout}
        isLogin={isLogin}
      />
    );
  }
}
