import { Record } from "immutable";
import * as base64 from "base-64";
import { Account } from "taiyaq-web-api";

interface TokenInterface {
  exp: number;
  sub: string;
}
interface LoginInterface {
  name: string;
  image: string | undefined;
  point: number;
  countOfContents: number;
}

const LoginRecord = Record(<LoginInterface>{
  name: "",
  image: undefined,
  point: 0,
  countOfContents: 0
});

export default class Login extends LoginRecord implements LoginInterface {
  name: string;
  image: string | undefined;
  point: number;
  countOfContents: number;

  clearToken(): void {
    sessionStorage.removeItem("signedtoken");
  }
  getToken(): string {
    return sessionStorage.getItem("signedtoken") || "";
  }
  parseToken(): TokenInterface | undefined {
    const subToken = (token: string): string => {
      return token.substring(token.indexOf(".") + 1, token.lastIndexOf("."));
    };

    try {
      const token = this.getToken();
      const next = JSON.parse(base64.decode(subToken(token)));
      if (next && next.exp) {
        return next;
      }
    } catch (e) {
      return;
    }
    return;
  }
  isLogin(): boolean {
    try {
      const token = this.parseToken();
      if (token) {
        const now = new Date().valueOf() / 1000;
        if (token.exp > now) {
          return true;
        }
      }
      return false;
    } catch (e) {
      return false;
    }
  }

  googleUserID(): string | undefined {
    if (this.isLogin()) {
      const token = this.parseToken() as TokenInterface;
      return token.sub;
    }
    return undefined;
  }
  setMyAccount(account: Account): Login {
    return <Login>this.withMutations(login => {
      let image: string | undefined = undefined;
      if (account.image !== "") {
        image = `data:image/png;base64,${account.image}`;
      }
      login.set("name", account.name);
      login.set("image", image);
      login.set("point", account.point);
      login.set("countOfContents", account.countOfContents);
      return login;
    });

    // return next;
  }
  logout(): Login {
    this.clearToken();
    let next = <Login>this.set("name", "").set("image", "");
    return next;
  }
  fetchOptions(option: Object | undefined = undefined): Object | undefined {
    if (!this.isLogin()) {
      throw new Error("loginToken expired!");
    }
    let addOption = {};
    if (option) {
      addOption = option;
    }
    return Object.assign(
      {},
      { headers: { Authorization: "Bearer " + this.getToken() } },
      addOption
    );
  }
}
