import * as React from "react";
import * as api from "taiyaq-web-api";
// UI
import Article from "taiyaq-ui/src/web2/article";
import { ActionDispatcherBase } from "./index";
import moment from "moment";
import "moment/locale/ja";

// models
import Feeds from "../../models/feeds";
import Accounts from "../../models/accounts";

export interface FeedClick {
  onClickTitle: (contentID: string) => void;
  onClickTag: (tagName: string) => void;
}

export interface Props {
  feeds: Feeds;
  accounts: Accounts;
  actions: ActionDispatcherBase;
}
export default class FeedBase<T extends Props> extends React.Component<T> {
  minifyURL = (url: string) => {
    const maxLength = 50;
    if (url.length > maxLength) {
      return url.substr(0, maxLength) + "...";
    }
    return url;
  };
  makeFeed = (clicks: FeedClick) => (c?: api.ContentTiny) => {
    const { accounts } = this.props;
    if (c === undefined) {
      return null;
    }
    const name = accounts.accounts.get(c.autherGoogleID).name;
    const img = accounts.images.get(c.autherGoogleID);
    return (
      <Article
        id={c.id}
        key={c.id}
        title={c.title}
        modifiedMessages={moment(c.modified).fromNow() + "に修正"}
        tags={c.tags || []}
        url={this.minifyURL(c.urls[0])}
        like={c.point}
        auther={name}
        imgURL={img}
        onClickTitle={() => clicks.onClickTitle(c.id)}
        onClickTag={tag => clicks.onClickTag(tag)}
      />
    );
  };
}
